/**
 * Log types for the server-side console capture.
 */
export type LogLevel = 'log' | 'info' | 'warn' | 'error' | 'debug' | 'trace';
export interface CapturedLog {
    timestamp: number;
    level: LogLevel;
    message: string;
    args: string[];
    repeatCount?: number;
}
export interface LogQuery {
    count?: number;
    level?: LogLevel | LogLevel[];
    pattern?: string;
    since?: number;
    until?: number;
}
export interface ManagedBrowser {
    close(): Promise<void>;
    page: unknown;
    /** Query captured console logs. */
    queryLogs(options?: LogQuery): CapturedLog[];
    /** Read the managed browser tab identity used by MCP metadata. */
    getTabMetadata(): Promise<{
        id: string | null;
        generation: number | null;
    }>;
    /** Take a screenshot of the browser page via CDP. */
    screenshot(): Promise<Buffer>;
    /** Register a callback invoked when the page/browser closes unexpectedly. */
    onClose(callback: () => void): void;
    /** Whether the underlying Playwright page has been closed. */
    isClosed(): boolean;
}
export declare function launchManagedBrowser(url: string, headless: boolean, verbose: boolean, viewport?: {
    width: number;
    height: number;
} | null, screenshotSize?: {
    width: number;
    height: number;
}, traceMcp?: boolean): Promise<ManagedBrowser>;
